#include <stdio.h>

int main() {
    int n, m;
    scanf("%d %d", &n, &m);

    int arr1[n], arr2[m];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr1[i]);
    }
    for (int i = 0; i < m; i++) {
        scanf("%d", &arr2[i]);
    }

    int intersection[n < m ? n : m], intersection_size = 0;

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (arr1[i] == arr2[j]) {
                int already_exists = 0;
                for(int k = 0; k < intersection_size; k++){
                    if(intersection[k] == arr1[i]){
                        already_exists = 1;
                        break;
                    }
                }
                if(!already_exists){
                    intersection[intersection_size++] = arr1[i];
                }
                break;
            }
        }
    }

    // Sorting the output array
    for (int i = 0; i < intersection_size - 1; i++) {
        for (int j = 0; j < intersection_size - i - 1; j++) {
            if (intersection[j] > intersection[j + 1]) {
                int temp = intersection[j];
                intersection[j] = intersection[j + 1];
                intersection[j + 1] = temp;
            }
        }
    }

    for (int i = 0; i < intersection_size; i++) {
        printf("%d", intersection[i]);
        if (i < intersection_size - 1) {
            printf(" ");
        }
    }
    printf("\n");

    return 0;
}
